/**
 * Per-item icon overrides, scraped from levelupgateway.com (its /actions/*.svg
 * icon set, ~314 icons under assets/icons/actions/). AUTO-GENERATED. Keys are item
 * names normalized to lowercase alphanumerics (see iconKey). Used to give weapons,
 * maneuvers, gear and class features the same icons the official builder uses.
 */
const ICON_BASE = 'modules/a5e-mancer/assets/icons/actions/';

/** Normalize an item name to its lookup key (lowercase, alphanumerics only). */
export function iconKey(name) {
  return (name ?? '').toLowerCase().replace(/[^a-z0-9]/g, '');
}

